#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

// Distance calculation kernel
kernel void dist_kernel(
    const global Point_Struct* p,
    const global float* coord,
    global float* work_mem,
    const global int* center_table,
    global char* switch_membership,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    // Calculate distance from point i to point x
    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - coord[d * num + x];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += x_cost - current_cost;
    } else {
        int assign = p[i].assign;
        int ct = center_table[assign];
        if (ct >= 0 && ct < K) {
            work_mem[i * (K + 1) + ct] += current_cost - x_cost;
        }
    }
}

// Center evaluation kernel
kernel void center_eval_kernel(
    const global float* work_mem,
    global float* gl_lower,
    const global int* center_table,
    const global char* is_center,
    const int num,
    const int K,
    const float z)
{
    int i = get_global_id(0);
    if (i >= num) return;

    if (is_center[i]) {
        float low = z;
        int ct = center_table[i];
        if (ct >= 0 && ct < K) {
            for (int j = 0; j < num; j++) {
                low += work_mem[j * (K + 1) + ct];
            }
            gl_lower[ct] = low;
        }
    }
}

// Update assignments kernel
kernel void update_assign_kernel(
    global Point_Struct* p,
    const global float* coord,
    const global char* switch_membership,
    const global float* gl_lower,
    const global int* center_table,
    const global int* is_center_flag,
    const int num,
    const int dim,
    const long x,
    const int gl_cost_negative)
{
    int i = get_global_id(0);
    if (i >= num) return;

    if (gl_cost_negative) {
        int assign = p[i].assign;
        int ct = center_table[assign];
        bool close_center = (ct >= 0 && gl_lower[ct] > 0);

        if (switch_membership[i] || close_center) {
            float new_cost = 0.0f;
            for (int d = 0; d < dim; d++) {
                float diff = coord[d * num + i] - coord[d * num + x];
                new_cost += diff * diff;
            }
            p[i].cost = new_cost * p[i].weight;
            p[i].assign = x;
        }

        if (is_center_flag[i] && ct >= 0 && gl_lower[ct] > 0) {
            is_center_flag[i] = 0;
        }

        if (i == x) {
            is_center_flag[i] = 1;
        }
    }
}

// Aggregate work_mem kernel
kernel void aggregate_kernel(
    global float* work_mem,
    const int num,
    const int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    // Each thread processes one row of work_mem
    for (int k = 0; k < K + 1; k++) {
        work_mem[i * (K + 1) + k] = 0.0f;
    }
}

// Copy coordinates to device format kernel
kernel void copy_coord_kernel(
    global float* coord_d,
    const global float* coord_h,
    const int num,
    const int dim)
{
    int idx = get_global_id(0);
    int total = num * dim;
    if (idx >= total) return;

    coord_d[idx] = coord_h[idx];
}

// Initialize point structure kernel
kernel void init_point_kernel(
    global Point_Struct* p_d,
    const global float* weights,
    const global long* assigns,
    const global float* costs,
    const int num)
{
    int i = get_global_id(0);
    if (i >= num) return;

    p_d[i].weight = weights[i];
    p_d[i].assign = assigns[i];
    p_d[i].cost = costs[i];
}
